SELECT l.id, l.user_id, l.target_type, l.target_id as like_target_id, l.deleted, l.create_time, a.id as article_id, a.title, a.avatar, a.summary, a.view_count, a.like_count, a.create_time as article_create_time, s.id as say_id, s.content as say_content, s.images as say_images, s.like_count as say_like_count, s.comment_count as say_comment_count, s.create_time as say_create_time, t.id as treehole_id, t.content as treehole_content, t.like_count as treehole_like_count, t.comment_count as treehole_comment_count, t.create_time as treehole_create_time FROM b_like_record l LEFT JOIN b_article a ON l.target_type = 'article' AND l.target_id = a.id AND a.deleted = 0 LEFT JOIN b_say s ON l.target_type = 'say' AND l.target_id = s.id AND s.deleted = 0 LEFT JOIN b_treehole t ON l.target_type = 'treehole' AND l.target_id = t.id AND t.deleted = 0 WHERE l.deleted = 0 AND l.user_id = #{userId} AND l.target_type = #{targetType}
AND ( (l.target_type = 'article' AND a.id IS NOT NULL) OR (l.target_type = 'say' AND s.id IS NOT NULL) OR (l.target_type = 'treehole' AND t.id IS NOT NULL) )
ORDER BY l.create_time DESC
